// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.benchmark.LmdbRegressionAnalysisSupport.CapturedRegressionSnapshot;
import org.junit.jupiter.api.Assumptions;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbRegressionPlanCaptureTest {

	private static final String ENABLED_PROPERTY = "rdf4j.lmdb.regressionCapture.enabled";
	private static final String OUTPUT_DIR_PROPERTY = "rdf4j.lmdb.regressionCapture.outputDir";
	private static final String QUERY_KEYS_PROPERTY = "rdf4j.lmdb.regressionCapture.queryKeys";

	@Test
	void captureCurrentRegressionSnapshots(@TempDir Path dataDir) throws Exception {
		Assumptions.assumeTrue(Boolean.getBoolean(ENABLED_PROPERTY),
				"Set -" + "D" + ENABLED_PROPERTY + "=true to capture current LMDB regression snapshots");

		Path outputDir = resolveOutputDirectory();
		List<LmdbRegressionAnalysisSupport.TargetQuery> targetQueries = LmdbRegressionAnalysisSupport
				.resolveTargetQueries(System.getProperty(QUERY_KEYS_PROPERTY, ""));
		List<CapturedRegressionSnapshot> capturedSnapshots = LmdbRegressionAnalysisSupport
				.captureCurrentRegressionSnapshots(dataDir, outputDir, targetQueries);
		Path summaryPath = LmdbRegressionAnalysisSupport.writeSummary(outputDir, capturedSnapshots);

		assertFalse(capturedSnapshots.isEmpty(), "Expected captured regression snapshots");
		assertEquals(targetQueries.size(), capturedSnapshots.size(),
				"Expected one snapshot per targeted regression query");
		assertTrue(Files.isRegularFile(summaryPath), "Expected summary file at " + summaryPath);
		for (CapturedRegressionSnapshot snapshot : capturedSnapshots) {
			assertTrue(Files.isRegularFile(snapshot.snapshotPath()),
					"Expected snapshot file at " + snapshot.snapshotPath());
		}
	}

	private static Path resolveOutputDirectory() {
		String configured = System.getProperty(OUTPUT_DIR_PROPERTY, "").trim();
		if (!configured.isEmpty()) {
			return Path.of(configured);
		}
		return LmdbRegressionAnalysisSupport.defaultOutputDirectory();
	}
}
